interface.definition:
#"SYSTEM_SYSRULES_formLayout"(
  titleBar: #"SYSTEM_SYSRULES_headerTemplateSimple"(
    title: "Create / Update ApiConfiguration",
    secondaryText: "Fill in the fields below and click Save."
  ),
  contents: {
    #"SYSTEM_SYSRULES_textField"(label: "apiName", value: ri!record.apiName, saveInto: ri!record.apiName, required: true),
    #"SYSTEM_SYSRULES_textField"(label: "apiEndpoint", value: ri!record.apiEndpoint, saveInto: ri!record.apiEndpoint, required: true),
    #"SYSTEM_SYSRULES_textField"(label: "apiKey", value: ri!record.apiKey, saveInto: ri!record.apiKey, required: true),
    #"SYSTEM_SYSRULES_checkboxField_v1"(label: "isActive", value: ri!record.isActive, saveInto: ri!record.isActive, choiceLabels: {"Yes"}, choiceValues: {true}),
    #"SYSTEM_SYSRULES_integerField"(label: "rateLimitPerHour", value: ri!record.rateLimitPerHour, saveInto: ri!record.rateLimitPerHour),
    #"SYSTEM_SYSRULES_integerField"(label: "timeoutSeconds", value: ri!record.timeoutSeconds, saveInto: ri!record.timeoutSeconds)
  },
  buttons: #"SYSTEM_SYSRULES_buttonLayout"(
    primaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Save", submit: true, style: "PRIMARY")
    },
    secondaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Cancel", value: true, saveInto: ri!cancel, submit: true, validate: false)
    }
  )
)
